//! WASM Module Validator
//! Generated by Python
//!
//! Validates that a module is well-formed according to the spec.

use super::types::*;
use super::decoder::Module;
use std::collections::HashSet;

pub struct Validator {
    errors: Vec<String>,
}

impl Validator {
    pub fn new() -> Self {
        Self { errors: Vec::new() }
    }

    /// Validate entire module
    pub     fn validate(&mut self, module: &Module) -> WasmResult<()> {
        self.errors.clear();

        // Validate types
        for (i, func_type) in module.types.iter().enumerate() {
            if func_type.params.len() > 1000 {
                self.add_error(format!("Function type {} has too many params", i));
            }
        }

        // Validate function bodies
        let num_imports = module.imports.iter()
            .filter(|i| matches!(i.kind, super::decoder::ImportKind::Function(_)))
            .count();

        for (i, func_type_idx) in module.functions.iter().enumerate() {
            if *func_type_idx as usize >= module.types.len() {
                return Err(WasmError::InvalidTypeIndex(*func_type_idx));
            }
            let func_type = &module.types[*func_type_idx as usize];
            if let Some(body) = module.code.get(i) {
                self.validate_function_body(body, func_type, &module.types)?;
            }
        }

        // Validate exports
        for export in &module.exports {
            match export.kind {
                super::decoder::ExportKind::Function(idx) => {
                    let total = num_imports + module.functions.len();
                    if idx as usize >= total {
                        self.add_error(format!("Export references invalid function: {}", idx));
                    }
                }
                super::decoder::ExportKind::Memory(idx) => {
                    if idx as usize >= module.memories.len() {
                        self.add_error(format!("Export references invalid memory: {}", idx));
                    }
                }
                super::decoder::ExportKind::Global(idx) => {
                    if idx as usize >= module.globals.len() {
                        self.add_error(format!("Export references invalid global: {}", idx));
                    }
                }
                super::decoder::ExportKind::Table(idx) => {
                    if idx as usize >= module.tables.len() {
                        self.add_error(format!("Export references invalid table: {}", idx));
                    }
                }
            }
        }

        // Check for duplicate exports
        let mut names = HashSet::new();
        for export in &module.exports {
            if !names.insert(&export.name) {
                self.add_error(format!("Duplicate export: {}", export.name));
            }
        }

        if self.errors.is_empty() {
            Ok(())
        } else {
            Err(WasmError::Validation(self.errors.join("; ")))
        }
    }

    fn validate_function_body(&self, body: &super::decoder::FunctionBody, func_type: &FuncType, types: &[FuncType]) -> WasmResult<()> {
        // Basic validation - check that code size is reasonable
        if body.code.is_empty() {
            return Err(WasmError::Validation("Empty function body".to_string()));
        }

        // Count parameters and locals
        let param_count = func_type.params.len();
        let mut local_count = param_count;
        for (count, _) in &body.locals {
            local_count += *count as usize;
        }

        if local_count > 50000 {
            return Err(WasmError::Validation("Too many locals".to_string()));
        }

        // Validate that the code ends with 'end' opcode
        if body.code.last() != Some(&0x0B) {
            return Err(WasmError::Validation("Function body must end with 'end'".to_string()));
        }

        // Validate result type matches
        let _ = types; // Avoid unused warning

        Ok(())
    }

    fn add_error(&mut self, msg: String) {
        self.errors.push(msg);
    }
}

impl Default for Validator {
    fn default() -> Self {
        Self::new()
    }
}
